text:
&.btn-lg {
    .btn-lg; /* reference to admin-lte/buttons.less */

    span.ui-icon {
        width: 22px;
        height: 20px;
        margin-top:-8px;
        &:before {
            font-size: @font-awesome-icon2x-size
        }
    }

    &.ui-button-text-icon-right, &.ui-button-text-icon-left  {
        padding: 6px 16px;
    }
}

> a {
  padding: 5px 5px 5px 15px;
  display: block;
  font-size: 14px;
  > .fa,
  > .glyphicon,
  > .ion {
    width: 20px;
  }
  > .pull-right-container > .fa-angle-left,
  > .pull-right-container > .fa-angle-down,
  > .fa-angle-left,
  > .fa-angle-down {
    width: auto;
  }
}

img {
  position: relative;
  display: block;
  max-width: 100%;
  max-height: 100%;
  //max-width:100%;
  //height:auto;
  opacity: 0;
  z-index: 200;
  -webkit-user-drag: none;
  transition: opacity .2s ease-in;

  &.@{ns}img-loaded {
    opacity: 1;
  }
}

&[data-site-mode='true'] {
  padding-top: @s-nav-height + 50px;

  &[data-show-sidemenu='true'] {
    padding-left: @s-site-menu-width + 50px;
  }

  .@{prefix}-layout-content > .markdown:first-child > *:first-child {
    margin-top: 0;
  }

  .@{prefix}-layout-toc {
    top: 114px;
    max-height: calc(90vh - 144px);
  }
}

footer.dark {
  background-color: #000;
  color: rgba(255, 255, 255, 0.65);
  a {
    color: rgba(255, 255, 255, 0.9);
  }
  h2 {
    color: rgba(255, 255, 255, 1);
    & >span {
      color: rgba(255, 255, 255, 1);
    }
  }
  .bottom-bar {
    overflow: hidden;
  }
}

&-footer {
  display: flex;
  width: 100%;
  align-items: center;
  border-top: 1rpx solid @border-color-base;
  padding: 10px 0;
  margin: -4px 0 0;
  font-size: 14px;
  line-height: 20px;
  color: @color-text-caption;
  image {
    width: 14px;
    height: 14px;
    margin-right: 4px;
  }
}

#MathJax_AboutClose,
    #MathJax_HelpClose {
      border-color: @surface2;
      color: @subtext0;
      span {
        background-color: @surface2;
      }

      &:hover {
        color: @text !important;
        border-color: @overlay0 !important;
        span {
          background-color: @overlay0 !important;
        }
      }
    }

pre {
  background: var(--r-bg);
  border: 1px solid var(--r-line);
  border-radius: 0;
  padding: 14px 18px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  overflow-x: auto;

  code {
    background: transparent;
    border: none;
    padding: 0;
    color: var(--r-text);
  }
}

&-small{
    th{
        height: 32px;
    }
    td{
        height: 40px;
    }
    &-title, &-footer{
        height: 40px;
        line-height: 40px;
    }
    .@{table-prefix-cls}-cell-with-expand{
        height: 39px;
        line-height: 39px;
    }
}

@media screen and (min-width: 600px) {

    ::-webkit-scrollbar-thumb {
        background: var(--dark-primary);
    }

    ::-webkit-scrollbar-thumb:hover {
        background: var(--dark-primary);
    }

    ::-webkit-scrollbar-thumb:active {
        background: var(--dark-primary);
    }
}

#config-items-list {
  :is(th, td) {
    padding: 8px 12px;
  }
  :is(tr:hover, td.gray) {
    background-color: @color-fade2;
  }
  th,
  td:not(:last-child) {
    border-color: @border-darker;
  }
  :is(.envvar_prefix, td.redacted) {
    opacity: 1;
    color: @color-fade5;
  }
}

&.progress-active {
	cursor: progress;

	.rest {
		.transform(translate3d(0,-100%,0));
		opacity: 0;
	}
    .active {
		.transform(translate3d(0, -50%,0));
		opacity: 1;
	}


	&:before { .transform(translateY(0%)); }
	.progress-bar { .transform(translateX(0%));}
}

#loading-message {
  text-align: center;
  font-size: 28px;
  font-weight: 200;
  color: white;
  position: absolute;
  left: 50%;
  top: 50%;
  height: 28px;
  width: 100%;
  transform: translate(-50%, -50%);
  img {
    vertical-align: middle;
    margin-bottom: 4px;
  }
}

&__dialog-table-item {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;

  &:nth-child(even) {
    background: var(--tv-PopUpload-table-item-even-bg-color);
  }

  .del-col {
    color: var(--tv-PopUpload-dialog-delete-text-color);
    width: 100%;
    cursor: pointer;
  }
}

&.is-current {
  > .@{tree-node-prefix-cls}__content {
    @apply relative;
    @apply bg-color-bg-3;

    &::after {
      @apply content-[''];
      @apply border-r-2 border-r-color-brand;
      @apply absolute;
      @apply top-0;
      @apply left-0;
      @apply h-full;
      @apply ~'z-[1]';
    }
  }
}

&[x-placement^='top'] {
  @apply mb-3;

  .popper__arrow {
    @apply ~'-bottom-1.5';
    @apply border-t-color-text-primary;
    @apply border-b-0;

    &::after {
      @apply bottom-px;
      margin-left: -5px;
      @apply border-t-color-text-primary;
      @apply border-b-0;
    }
  }
}

&[x-placement^='bottom'] {
  @apply mt-3;

  .popper__arrow {
    @apply ~'-top-1.5';
    @apply border-t-0;
    @apply border-b-color-text-primary;

    &::after {
      @apply top-px;
      margin-left: -5px;
      @apply border-t-0;
      @apply border-b-color-text-primary;
    }
  }
}

&[x-placement^='right'] {
  @apply ml-3;

  .popper__arrow {
    @apply ~'-left-1.5';
    @apply border-r-color-text-primary;
    @apply border-l-0;

    &::after {
      bottom: -5px;
      @apply left-px;
      @apply border-r-color-text-primary;
      @apply border-l-0;
    }
  }
}

&-li {
  @apply h-8;
  @apply leading-8;
  @apply my-0 mx-2;
  @apply py-0 px-2;
  @apply rounded;
  @apply whitespace-nowrap;
  @apply overflow-hidden;
  @apply text-ellipsis;
  @apply cursor-pointer;

  &:hover {
    @apply bg-color-brand;
    @apply text-color-text-inverse;
  }
}

& &__oper-col-button {
  @apply text-sm;
  @apply cursor-pointer;
  @apply mr-2;

  > svg {
    @apply w-4;
    @apply h-4;
  }

  &--disabled {
    @apply cursor-not-allowed;
    @apply fill-color-icon-disabled;
    @apply text-color-text-disabled;
  }
}

&.active {
  border: 0;
  padding-top: 15px;
  background-color: @primary-color;
  color: var(--body-bg);

  .StatisticsWidget {
    &-heading {
      color: lighten(@primary-color, 30);
    }

    &-change {
      background-color: rgba(255, 255, 255, 0.2);
    }
  }
}

&-mask {
  position: fixed;
  top: 0;
  right: 0;
  left: 0;
  bottom: 0;
  background-color: rgb(55, 55, 55);
  background-color: rgba(55, 55, 55, 0.6);
  height: 100%;
  filter: alpha(opacity=50);
  z-index: 1050;

  &-hidden {
    display: none;
  }
}

&__dot {
  width: @step-item-dot-size;
  height: @step-item-dot-size;
  border-radius: 50%;
  border-width: 1px;
  border-style: solid;
  box-sizing: border-box;

  &--process {
    background-color: @step-item-process-dot-border-color;
  }

  &--error {
    background-color: @step-item-error-dot-border-color;
  }
}

&--outside {
  bottom: 0;

  .@{prefix}-swiper-nav {
    &__dots,
    &__dots-bar {
      &-item {
        background: @swiper-nav-outside-bg;

        &--active {
          background-color: @swiper-nav-outside-bg-active;
        }
      }
    }
  }
}

img.vh-article-img {
  box-sizing: border-box;
  padding: .36rem;
  width: max-content;
  max-width: 100%;
  max-height: 36rem;
  border: solid 1px var(--vh-font-16);
  border-radius: 5px;
  cursor: zoom-in;
  cursor: -moz-zoom-in;
  cursor: -webkit-zoom-in;

  &:not(.loaded) {
    width: 100%;
  }
}

&>.vh-img-flex {
  box-sizing: border-box;
  padding: 0.8rem 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(30%, 1fr));
  gap: 0.66rem;
  width: 100%;
  height: max-content;
  max-height: 50%;
  overflow: hidden;

  &>img {
    height: 100%;
    object-fit: cover;
  }
}

&-fixed, &-fixed-right{
    position: absolute;
    top: 0;
    left: 0;

    &::before {
        content: '';
        width: 100%;
        height: 1px;
        background-color: @border-color-base;
        position: absolute;
        left: 0;
        bottom: 0;
        z-index: 4;
    }
}

&.active {
    transform: scale(1);
    .verse {
        opacity:1 !important;
    }
    .verse-active {
        transition         : all 0.35s var(--appleEase);
        text-shadow        :
            3px 3px 0 #000,
            -1px -1px 0 #000,
            1px -1px 0 #000,
            -1px 1px 0 #000,
            1px 1px 0 #000;
    }

}

&--hairline {
  border-width: 0;

  &::after {
    border-color: inherit;
    border-radius: calc(var(--van-button-radius) * 2);
  }

  &.van-button--round::after {
    border-radius: var(--van-button-round-radius);
  }

  &.van-button--square::after {
    border-radius: 0;
  }
}

&-circle &-text {
  display: block;
  position: absolute;
  width: 100%;
  text-align: center;
  line-height: 1;
  top: 50%;
  transform: translateY(-50%);
  left: 0;
  font-family: tahoma;
  margin: 0;

  .@{iconfont-css-prefix} {
    font-size: 14 / 12em;
  }
}
